SELECT risk_score
FROM risk_assessment_logs
WHERE wallet_id = 0;

SELECT wallet_id
FROM risk_assessment_logs
ORDER BY assessment_date ASC;

SELECT AVG(combined_prob) AS average_combined_prob
FROM combined_risk
WHERE combined_prob > 50;

SELECT wallet_address, total_balance, creation_date
FROM wallets
ORDER BY creation_date DESC;
